#include <stdio.h>
#include <stdlib.h>

#define MEMORY_SIZE 1024

// Simulated OS Memory Management
typedef struct {
    int start;
    int size;
    int process_id;
    int allocated;
} MemoryBlock;

MemoryBlock memory[MEMORY_SIZE];

void init_memory() {
    // Initialize entire memory as one free block
    memory[0].start = 0;
    memory[0].size = MEMORY_SIZE;
    memory[0].process_id = -1;
    memory[0].allocated = 0;
}

// Simulates OS allocating memory to a process
int allocate_memory(int pid, int size) {
    for (int i = 0; i < MEMORY_SIZE; i++) {
        if (!memory[i].allocated && memory[i].size >= size) {
            // Found suitable block
            int remaining = memory[i].size - size;

            // Allocate block
            memory[i].allocated = 1;
            memory[i].process_id = pid;
            memory[i].size = size;

            // Split if there's remaining space
            if (remaining > 0) {
                memory[i+1].start = memory[i].start + size;
                memory[i+1].size = remaining;
                memory[i+1].process_id = -1;
                memory[i+1].allocated = 0;
            }

            printf("OS: Allocated %d bytes to Process %d at address %d\n", 
                   size, pid, memory[i].start);
            return memory[i].start;
        }
    }
    printf("OS: Memory allocation failed for Process %d\n", pid);
    return -1;
}

// Simulates OS freeing memory when process terminates
void free_memory(int pid) {
    for (int i = 0; i < MEMORY_SIZE; i++) {
        if (memory[i].allocated && memory[i].process_id == pid) {
            printf("OS: Freed memory for Process %d\n", pid);
            memory[i].allocated = 0;
            memory[i].process_id = -1;
            // In real OS: merge adjacent free blocks
        }
    }
}

int main() {
    init_memory();

    // Simulate processes requesting memory
    allocate_memory(1, 200);  // Process 1 requests 200 bytes
    allocate_memory(2, 300);  // Process 2 requests 300 bytes
    allocate_memory(3, 100);  // Process 3 requests 100 bytes

    // Process 2 terminates, memory freed
    free_memory(2);

    // Process 4 requests memory
    allocate_memory(4, 150);  // May fit in freed space

    return 0;
}
